import{_ as t,o as a,c as n,a2 as r}from"./chunks/framework.ufzXw1qY.js";const u=JSON.parse('{"title":"Governance Overview — OpenSIN-AI Fleet Governance","description":"","frontmatter":{},"headers":[],"relativePath":"governance/overview.md","filePath":"governance/overview.md"}'),o={name:"governance/overview.md"};function i(d,e,l,s,c,h){return a(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="governance-overview-—-opensin-ai-fleet-governance" tabindex="-1">Governance Overview — OpenSIN-AI Fleet Governance <a class="header-anchor" href="#governance-overview-—-opensin-ai-fleet-governance" aria-label="Permalink to &quot;Governance Overview — OpenSIN-AI Fleet Governance&quot;">​</a></h1><p><strong>Status:</strong> Active <strong>Owner:</strong> SIN-Zeus (control-plane)</p><hr><h2 id="what-is-governance" tabindex="-1">What Is Governance? <a class="header-anchor" href="#what-is-governance" aria-label="Permalink to &quot;What Is Governance?&quot;">​</a></h2><p>Governance defines the rules, processes, and automated checks that keep the OpenSIN-AI fleet operating safely, consistently, and in alignment with organizational standards. Governance is not optional — it is enforced through automated checks, PR-watcher hooks, and fleet-wide mandates.</p><hr><h2 id="governance-layers" tabindex="-1">Governance Layers <a class="header-anchor" href="#governance-layers" aria-label="Permalink to &quot;Governance Layers&quot;">​</a></h2><h3 id="_1-repo-governance" tabindex="-1">1. Repo Governance <a class="header-anchor" href="#_1-repo-governance" aria-label="Permalink to &quot;1. Repo Governance&quot;">​</a></h3><p>Every repository in the OpenSIN-AI organization must comply with minimum standards:</p><ul><li><code>README.md</code> with project description</li><li><code>AGENTS.md</code> with agent operating manual</li><li><code>LICENSE</code> file</li><li><code>.gitignore</code> configuration</li><li>GitHub Topics (at least 1)</li><li>No hardcoded secrets</li></ul><p>Enforced by: <a href="/governance/repo-health-check.html">Repo Health Check</a> GitHub Action</p><h3 id="_2-code-governance" tabindex="-1">2. Code Governance <a class="header-anchor" href="#_2-code-governance" aria-label="Permalink to &quot;2. Code Governance&quot;">​</a></h3><ul><li><strong>PR-Watcher</strong>: Every PR is automatically reviewed by 5 parallel sub-agents</li><li><strong>Commit Hooks</strong>: <code>.opencode/opencode.json</code> hooks inject Global Brain context</li><li><strong>Code Quality</strong>: LSP diagnostics, AST-grep patterns, test coverage gates</li></ul><h3 id="_3-fleet-governance" tabindex="-1">3. Fleet Governance <a class="header-anchor" href="#_3-fleet-governance" aria-label="Permalink to &quot;3. Fleet Governance&quot;">​</a></h3><ul><li><strong>Agent Mandates</strong>: Priority-ranked rules in <code>AGENTS.md</code> (P-100 to P0)</li><li><strong>Technology Bans</strong>: Camoufox, Playwright, Puppeteer, Selenium permanently banned</li><li><strong>Package Manager</strong>: Bun only — npm is permanently banned</li><li><strong>LLM Routing</strong>: Only approved models via <code>opencode</code> CLI</li></ul><h3 id="_4-auth-governance" tabindex="-1">4. Auth Governance <a class="header-anchor" href="#_4-auth-governance" aria-label="Permalink to &quot;4. Auth Governance&quot;">​</a></h3><ul><li><strong>Antigravity Plugin</strong>: Must never be removed from opencode.json</li><li><strong>Token Rotation</strong>: Automated via OCI VM token factory</li><li><strong>Supabase Pool</strong>: Centralized token management with <code>is_active</code> boolean</li></ul><hr><h2 id="key-governance-agents" tabindex="-1">Key Governance Agents <a class="header-anchor" href="#key-governance-agents" aria-label="Permalink to &quot;Key Governance Agents&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Agent</th><th>Role</th><th>Mandate</th></tr></thead><tbody><tr><td><strong>SIN-Zeus</strong></td><td>Fleet Commander</td><td>Top-level orchestration, audit, compliance</td></tr><tr><td><strong>SIN-Hermes</strong></td><td>Task Dispatcher</td><td>Routes tasks, monitors fleet health</td></tr><tr><td><strong>SIN-Herakles</strong></td><td>Backend/Infra</td><td>Heavy lifting, system operations</td></tr><tr><td><strong>PR-Watcher</strong></td><td>Code Review</td><td>Automated PR analysis (5 parallel agents)</td></tr><tr><td><strong>Box Storage Agent</strong></td><td>Artifact Management</td><td>Uploads logs/screenshots to Box.com, auto-creates issues</td></tr></tbody></table><hr><h2 id="governance-documents" tabindex="-1">Governance Documents <a class="header-anchor" href="#governance-documents" aria-label="Permalink to &quot;Governance Documents&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Document</th><th>Purpose</th></tr></thead><tbody><tr><td><a href="/governance/repo-health-check.html">Repo Health Check</a></td><td>Automated compliance checks</td></tr><tr><td><a href="/governance/domain-registry.html">Domain Registry</a></td><td>Evidence-based public / gated / internal surface map</td></tr><tr><td><a href="/governance/zeus.html">Zeus — Fleet Commander</a></td><td>Zeus operating manual</td></tr><tr><td><a href="/governance/hermes.html">Hermes — Task Dispatcher</a></td><td>Hermes operating manual</td></tr></tbody></table><hr><h2 id="violation-consequences" tabindex="-1">Violation Consequences <a class="header-anchor" href="#violation-consequences" aria-label="Permalink to &quot;Violation Consequences&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Violation</th><th>Consequence</th></tr></thead><tbody><tr><td>Banned technology usage</td><td>Immediate permanent ban</td></tr><tr><td>npm instead of bun</td><td>Immediate ban</td></tr><tr><td>Gemini API direct calls</td><td>Permanent ban</td></tr><tr><td>Web actions without Vision Gate</td><td>Permanent ban</td></tr><tr><td>Code without comments</td><td>Protocol violation</td></tr><tr><td>Assumptions without proof</td><td>Immediate ban</td></tr><tr><td>Bugs without GitHub Issues</td><td>Protocol violation</td></tr></tbody></table><hr><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/fleet/overview.html">Fleet Overview</a></li><li><a href="/governance/repo-health-check.html">Repo Health Check</a></li><li><a href="/governance/domain-registry.html">Domain Registry</a></li><li><a href="/best-practices/agent-design.html">Agent Design Best Practices</a></li><li><a href="/architecture/security.html">Security Architecture</a></li></ul><hr><h2 id="relevante-mandate" tabindex="-1">Relevante Mandate <a class="header-anchor" href="#relevante-mandate" aria-label="Permalink to &quot;Relevante Mandate&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mandat</th><th>Priority</th><th>Regel</th></tr></thead><tbody><tr><td><strong>Immediate Bug Registry</strong></td><td>-4.0</td><td>JEDER Bug SOFORT als GitHub Issue</td></tr><tr><td><strong>PR-Watcher</strong></td><td>0.0</td><td>Alle Repos brauchen PR-Watcher</td></tr><tr><td><strong>Zeus/Hermes</strong></td><td>0.0</td><td>Fleet-Kommando via SIN-Zeus</td></tr></tbody></table><p>→ <a href="/best-practices/error-handling.html">Alle Mandate</a></p>',33)])])}const m=t(o,[["render",i]]);export{u as __pageData,m as default};
